// Propósito: Combinar respuestas de BCRA + NOSIS + PLENARIO con el contexto
// ============================================================

const items = $input.all();

// Separar respuestas por sistema
const bcraData = items.find(item => item.json.sistema === "bcra");
const nosisData = items.find(item => item.json.sistema === "nosis");
//const plenarioData = items.find(item => item.json.sistema === "plenario");
const plenarioEmisor = items.find(item => item.json.sistema === "plenarioEmisor");
const plenarioAsociado = items.find(item => item.json.sistema === "plenarioAsociado");

// Log para debugging
console.log('📦 Items recibidos:', items.length);
console.log('🏛️ BCRA encontrado:', !!bcraData);
console.log('📋 NOSIS encontrado:', !!nosisData);
//console.log('💼 PLENARIO encontrado:', !!plenarioData);

// Obtener contexto original del cheque
const contextoOriginal = $('prepararContextAI').first().json;

// Construir texto unificado con las tres validaciones
const textoCompleto = 
  contextoOriginal.text + 
  (bcraData?.json.texto || "\n\n🏛️ **BCRA:** ⏳ No disponible\n") + 
  (nosisData?.json.texto || "\n\n📋 **NOSIS:** ⏳ No disponible\n") +
  (plenarioEmisor?.json.texto || "\n\n💼 **PLENARIO:** ⏳ No disponible\n") +
  (plenarioAsociado?.json.texto || "\n\n💼 **PLENARIO:** ⏳ No disponible\n");

// Combinar datos estructurados de las cuatro fuentes
return [{
  json: {
    ...contextoOriginal,
    text: textoCompleto,
    validaciones: {
      bcra: bcraData?.json.datos || null,
      nosis: nosisData?.json.datos || null,
      plenario_emisor: plenarioEmisor?.json.datos || null,
      plenario_asociado: plenarioAsociado?.json.datos || null
    },
    validaciones_status: {
      bcra: bcraData?.json.status || "error",
      nosis: nosisData?.json.status || "error",
      plenario_emisor: plenarioEmisor?.json.status || "error",
      plenario_asociado: plenarioAsociado?.json.status || "error"
    },
    timestamp_validaciones: new Date().toISOString()
  }
}];

// Función para convertir número WhatsApp a formato argentino
