{
  "type": "object",
  "properties": {
    "response": {
      "type": "string",
      "description": "La respuesta conversacional para el usuario"
    },
    "should_register": {
      "type": "boolean",
      "description": "true si la conversación contiene información valiosa para registrar, false en caso contrario"
    },
    "context_data": {
      "type": "object",
      "properties": {
        "mensaje": {
          "type": "string",
          "description": "Descripción breve y clara de la información relevante del usuario (presupuesto, preferencias, necesidades)"
        },
        "etapa": {
          "type": "string",
          "enum": ["Abierta", "Desarrollada", "Cierre"],
          "description": "Etapa actual del proceso de venta"
        },
        "modelo": {
          "type": "string",
          "description": "Nombre del modelo de vehículo si es relevante, vacío si no aplica"
        },
        "nombre": {
          "type": "string",
          "description": "Nombre del cliente si fue capturado en la conversación"
        }
      },
      "required": ["mensaje", "etapa", "modelo", "nombre"]
    },
    "cierre_data": {
      "type": "object",
      "properties": {
        "tipo_operacion": {
          "type": ["string", "null"],
          "enum": ["plan_ahorro", "venta_directa", null],
          "description": "Tipo de operación detectado. null si etapa no es Cierre"
        },
        "sucursal": {
          "type": ["string", "null"],
          "enum": ["tucuman", "santiago_del_estero", null],
          "description": "Sucursal derivada del origen del cliente. null si etapa no es Cierre o si falta origen"
        },
        "equipo_crm": {
          "type": ["string", "null"],
          "enum": [
            "tucuman_venta_directa",
            "tucuman_plan_ahorro",
            "santiago_del_estero_venta_directa",
            "santiago_del_estero_plan_ahorro",
            null
          ],
          "description": "Combinación sucursal + tipo_operacion para distribución en CRM. null si faltan datos o etapa no es Cierre"
        }
      },
      "required": ["tipo_operacion", "sucursal", "equipo_crm"]
    }
  },
  "required": ["response", "should_register", "context_data", "cierre_data"]
}

