// Obtener sessionId del nodo session-id
const sessionId = $('session-id').first().json.sessionId;

// Obtener datos del AI
const aiOutput = $('Nissan-Vendedor-Orquestador').first().json.output;
const contextData = aiOutput.context_data || {};
const aiResponse = aiOutput.response || '';

// Obtener mensaje del usuario
const userMessages = $('une_mensajes').first().json;
const userMessage = userMessages.mensaje_usuario || '';

// Crear el objeto que se guardará en Redis
const redisData = {
  timestamp: new Date().toISOString(),
  etapa: contextData.etapa || 'Abierta',
  last_bot_msg: aiResponse,
  last_user_msg: userMessage,
  nombre: contextData.nombre || ''
};

// Convertir a JSON string
const redisValue = JSON.stringify(redisData);

// Retornar para el siguiente nodo
return {
  json: {
    redis_key: `followup_nissan:${sessionId}`,
    redis_value: redisValue,
    ttl: 86400 // 24 horas
  }
};

